link.script:
jQuery(document).ready(function($){initialiseBookmarkedPost()});function getBookmarkedPostsArray(){if(Cookies.get('bookmarkedPosts')){var bookmarkedPosts=JSON.parse(Cookies.get('bookmarkedPosts'));if(typeof bookmarkedPosts==='undefined'){bookmarkedPosts=[]}}else{bookmarkedPosts=[]}return bookmarkedPosts}function bookmarkedPost(id){var bookmarkedPosts=getBookmarkedPostsArray();if(bookmarkedPosts.indexOf(id)===-1){bookmarkedPosts.push(id)}Cookies.set('bookmarkedPosts',JSON.stringify(bookmarkedPosts),{expires:365})}function clearBookmarkedPost(id){var bookmarkedPosts=getBookmarkedPostsArray();var index=bookmarkedPosts.indexOf(id);if(index!==-1){bookmarkedPosts.splice(index,1)}Cookies.set('bookmarkedPosts',JSON.stringify(bookmarkedPosts),{expires:365})}function initialiseBookmarkedPost(){var bookmarkedPosts=getBookmarkedPostsArray();jQuery('#bookmarkPost').each(function(i,e){var post=jQuery(this);var fav=jQuery('.fav_Post');var bookmark_text=post.data('bookmark');var bookmarked_text=post.data('bookmarked');var favourite_text=fav.data('favourite');var remove_text=fav.data('remove');post.off('click').on('click',function(){updateBookmarkedButton(post,bookmark_text,bookmarked_text);updateBookmarkedButton(fav,favourite_text,remove_text)});setBookmarked(post,!(bookmarkedPosts.indexOf(getbookmarkPostId(post))===-1),bookmark_text,bookmarked_text)});jQuery('.fav_Post').each(function(i,e){var fav=jQuery(this);var post=jQuery('#bookmarkPost');var bookmark_text=post.data('bookmark');var bookmarked_text=post.data('bookmarked');var favourite_text=fav.data('favourite');var remove_text=fav.data('remove');fav.off('click').on('click',function(){updateBookmarkedButton(fav,favourite_text,remove_text);updateBookmarkedButton(post,bookmark_text,bookmarked_text)});setBookmarked(fav,!(bookmarkedPosts.indexOf(getbookmarkPostId(fav))===-1),favourite_text,remove_text)})}function updateBookmarkedButton(post,bookmark_text,bookmarked_text){var newMode=!getbookmarkedPostMode(post);setBookmarked(post,newMode,bookmark_text,bookmarked_text)}function setBookmarked(post,mode,bookmark_text,bookmarked_text){var fullText=jQuery.trim(post.html());var saveText=bookmark_text;var savedText=bookmarked_text;post.attr('data-saved',mode);if(mode){bookmarkedPost(getbookmarkPostId(post))
post.addClass('saved');fullText=fullText.replace(saveText,savedText)}else{clearBookmarkedPost(getbookmarkPostId(post))
post.removeClass('saved');if(fullText.indexOf(savedText)!=-1){fullText=fullText.replace(savedText,saveText)}}post.html(fullText)}function getbookmarkPostId(post){return parseInt(post.data('post-id'))}function getbookmarkedPostMode(post){return(post.attr('data-saved')==='true')}

div.script:
    function searchFetch(e) {
        var datafetch = e.parentElement.nextSibling
        if (e.value.trim().length > 0) {
            datafetch.style.display = "block";
        } else {
            datafetch.style.display = "none";
        }
        const searchForm = e.parentElement;
        e.nextSibling.value = "Please wait..."
        var formdata1 = new FormData(searchForm);
        formdata1.append("image", "true")
        formdata1.append("source", "post, page, course, vacancy, resource, vl_team_member")
        formdata1.append("action", "livesearch")
        Ajaxlivesearch(formdata1,e)
    }

    async function Ajaxlivesearch(formdata,e) {
        const url = "https://winchesterdiocese.org/wp-admin/admin-ajax.php?action=livesearch";
        const response = await fetch(url, {
            method: "POST",
            body: formdata,
        });
        const data = await response.text();
        if (data) {
            e.parentElement.nextSibling.innerHTML = data
        } else {
            e.parentElement.nextSibling.innerHTML = `
Sorry, nothing found`
        }
    }

    document.addEventListener("click", function(e) {
        if (document.activeElement.classList.contains("input_search") == false ) {
            [...document.querySelectorAll("div.search_result")].forEach(e => e.style.display = "none")
        } else {
            if (e.target.value.trim().length > 0) {
                e.target.parentElement.nextSibling.style.display = "block"
            }
        }
    })

